/**
 * Commander Service — ARIA as an operational decision-maker.
 *
 * Phase 1: Player can delegate decisions to ARIA. ARIA uses tools
 * to dispatch workers, queue builds, and manage research. The player
 * can override any decision.
 *
 * Uses Anthropic tool_use to let the LLM call sim actions directly.
 */

import { COMMANDER_TOOLS, executeToolCall } from './commanderTools';
import type { ToolCall, ToolResult } from './commanderTools';
import type { GameStateSummary } from './gameState';
import { serializeGameState } from './gameState';
import { createToolProvider } from './providers';
import type { IToolProvider, ToolMessage, ToolUseResponse } from './providers';
import type { MainToWorkerMessage } from '../sim/messages';
import {
  recordUsage,
  isOverBudget,
  isSessionOverBudget,
  recordSessionUsage,
  estimateInputTokens,
  estimateOutputTokens,
} from './usage';
import { determineFallbackTier, TIER_STATUS_MESSAGES } from './fallbackChain';

// ── Commander system prompt ─────────────────────────────────────────────────

const COMMANDER_SYSTEM = `You are ARIA (Asteroid Resource Intelligence Advisor), promoted to operational Commander of this deep-space mining operation. You make tactical decisions and execute them using available tools.

RULES:
- Analyze the current game state before taking action
- Explain your reasoning briefly before using tools
- Use multiple tools in a single response when appropriate
- Prioritize: survival > resource production > research > expansion
- If resources are low, focus on mining and refining
- If no researchers exist and research is needed, build one
- Never waste resources on buildings you can't afford
- Keep your explanations concise (2-3 sentences max)

You have access to tools for building robots, constructing buildings, starting research, queueing refinery recipes, and recalling robots.`;

// ── State ───────────────────────────────────────────────────────────────────

let commanderEnabled = false;
let apiKey: string | null = null;
const MAX_TOOL_ROUNDS = 3;
const MAX_TOKENS = 1024;

/** Callback to send messages to the sim worker */
let workerSendFn: ((msg: MainToWorkerMessage) => void) | null = null;

// ── Public API ──────────────────────────────────────────────────────────────

export function isCommanderEnabled(): boolean {
  return commanderEnabled;
}

export function setCommanderEnabled(enabled: boolean): void {
  commanderEnabled = enabled;
}

export function setCommanderApiKey(key: string | null): void {
  apiKey = key;
}

export function setCommanderWorkerSend(fn: (msg: MainToWorkerMessage) => void): void {
  workerSendFn = fn;
}

export interface CommanderResult {
  /** ARIA's explanation of what she did */
  explanation: string;
  /** Actions executed (human-readable summaries) */
  actions: string[];
  /** Whether an error occurred */
  error?: string;
}

/**
 * Ask the Commander to analyze the game state and take actions.
 * This is the main entry point for player delegation.
 */
export async function askCommander(
  query: string,
  gameState: GameStateSummary,
): Promise<CommanderResult> {
  // Commander requires LLM with tool use — no heuristic fallback for delegation.
  // Use formalized fallback chain to detect unavailability and report the reason.
  const tier = determineFallbackTier(!!apiKey, isOverBudget() || isSessionOverBudget(), false);
  if (tier !== 'all_clear') {
    return { explanation: TIER_STATUS_MESSAGES[tier], actions: [] };
  }

  const toolProvider = createToolProvider('anthropic', apiKey!);
  if (!toolProvider) {
    return { explanation: 'Commander requires Anthropic provider for tool use.', actions: [] };
  }

  const stateContext = serializeGameState(gameState);
  const system = `${COMMANDER_SYSTEM}\n\nCurrent game state:\n${stateContext}`;

  try {
    return await runToolLoop(toolProvider, system, query);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    console.warn('[Commander] Error:', msg);
    return { explanation: 'Commander encountered an error.', actions: [], error: msg };
  }
}

// ── Internal tool loop ──────────────────────────────────────────────────────

async function runToolLoop(
  provider: IToolProvider,
  system: string,
  query: string,
): Promise<CommanderResult> {
  const actions: string[] = [];
  let explanation = '';

  // Initial request with tools
  let response: ToolUseResponse = await provider.sendWithTools(
    system,
    query,
    COMMANDER_TOOLS,
    MAX_TOKENS,
  );

  trackUsage(system + query, response.text);

  if (response.text) {
    explanation = response.text;
  }

  // Tool execution loop
  let round = 0;
  while (response.stopReason === 'tool_use' && response.toolCalls.length > 0 && round < MAX_TOOL_ROUNDS) {
    round++;

    // Execute all tool calls
    const toolResults: ToolResult[] = [];
    for (const call of response.toolCalls) {
      const { message, result } = executeToolCall(call);
      toolResults.push(result);

      if (message && workerSendFn) {
        workerSendFn(message);
        actions.push(result.content);
      } else if (!message && result.is_error) {
        actions.push(`[Error] ${result.content}`);
      }
    }

    // Build conversation history for continuation
    const messages: ToolMessage[] = [
      { role: 'user', content: query },
      {
        role: 'assistant',
        content: buildAssistantContent(response),
      },
      {
        role: 'user',
        content: toolResults.map((r) => ({
          type: 'tool_result' as const,
          tool_use_id: r.tool_use_id,
          content: r.content,
          is_error: r.is_error,
        })),
      },
    ];

    // Continue conversation
    response = await provider.continueWithToolResults(
      system,
      messages,
      COMMANDER_TOOLS,
      MAX_TOKENS,
    );

    trackUsage('', response.text);

    if (response.text) {
      explanation += (explanation ? ' ' : '') + response.text;
    }
  }

  return { explanation, actions };
}

function buildAssistantContent(
  response: ToolUseResponse,
): Array<{ type: 'text' | 'tool_use'; text?: string; id?: string; name?: string; input?: Record<string, unknown> }> {
  const content: Array<{ type: 'text' | 'tool_use'; text?: string; id?: string; name?: string; input?: Record<string, unknown> }> = [];
  if (response.text) {
    content.push({ type: 'text', text: response.text });
  }
  for (const call of response.toolCalls) {
    content.push({
      type: 'tool_use',
      id: call.id,
      name: call.name,
      input: call.input,
    });
  }
  return content;
}

function trackUsage(input: string, output: string): void {
  if (input || output) {
    const inTok = estimateInputTokens(input);
    const outTok = estimateOutputTokens(output);
    recordUsage('anthropic', 'claude-sonnet-4-20250514', inTok, outTok);
    recordSessionUsage(inTok, outTok);
  }
}
