/**
 * Commander Tools — actions ARIA can execute in the sim.
 *
 * Each tool maps to an existing MainToWorkerMessage. The Commander
 * receives tool definitions in the LLM request and returns tool_use
 * blocks, which we execute by sending messages to the sim worker.
 */

import type { MainToWorkerMessage } from '../sim/messages';

// ── Tool schema (Anthropic tool_use format) ────────────────────────────────

export interface ToolDef {
  name: string;
  description: string;
  input_schema: Record<string, unknown>;
}

export const COMMANDER_TOOLS: ToolDef[] = [
  {
    name: 'build_robot',
    description:
      'Queue a robot for production in the factory. Types: 0=Scout, 1=Miner, 2=Hauler, 3=Researcher, 4=Refiner, 5=Defender, 6=Engineer. Factory must be built first.',
    input_schema: {
      type: 'object',
      properties: {
        robot_type: {
          type: 'number',
          description: 'Robot type enum (0-6)',
        },
      },
      required: ['robot_type'],
    },
  },
  {
    name: 'build_building',
    description:
      'Construct a building at the base. Types: 0=Factory, 1=Turret, 2=Relay, 3=SolarPanel, 4=Radiator, 5=SolarFurnace, 6=RTG, 7=FissionReactor, 8=FusionReactor. Requires the corresponding tech to be unlocked.',
    input_schema: {
      type: 'object',
      properties: {
        building_type: {
          type: 'number',
          description: 'Building type enum (0-8)',
        },
      },
      required: ['building_type'],
    },
  },
  {
    name: 'start_research',
    description:
      'Begin researching a tech node. Only one research can be active at a time. Prerequisites must be unlocked and resource costs are deducted.',
    input_schema: {
      type: 'object',
      properties: {
        node_id: {
          type: 'string',
          description: 'Tech node ID (e.g. "mining_basics", "ore_refining", "solar_collection")',
        },
      },
      required: ['node_id'],
    },
  },
  {
    name: 'enqueue_recipe',
    description:
      'Queue a refining recipe. Recipes: "smelt_iron", "smelt_nickel", "carbon_fiber", "silicon_wafer", "steel", "electronics". Requires refinery to be built.',
    input_schema: {
      type: 'object',
      properties: {
        recipe_id: {
          type: 'string',
          description: 'Recipe ID string',
        },
      },
      required: ['recipe_id'],
    },
  },
  {
    name: 'recall_robot',
    description: 'Order a specific robot to return to base immediately.',
    input_schema: {
      type: 'object',
      properties: {
        robot_eid: {
          type: 'number',
          description: 'Entity ID of the robot to recall',
        },
      },
      required: ['robot_eid'],
    },
  },
];

// ── Tool execution ─────────────────────────────────────────────────────────

export interface ToolCall {
  id: string;
  name: string;
  input: Record<string, unknown>;
}

export interface ToolResult {
  tool_use_id: string;
  content: string;
  is_error?: boolean;
}

/**
 * Execute a tool call by converting it to a sim worker message.
 * Returns the message to send and a human-readable result string.
 */
export function executeToolCall(call: ToolCall): {
  message: MainToWorkerMessage | null;
  result: ToolResult;
} {
  switch (call.name) {
    case 'build_robot': {
      const robotType = call.input.robot_type as number;
      if (robotType < 0 || robotType > 6) {
        return {
          message: null,
          result: { tool_use_id: call.id, content: 'Invalid robot type. Must be 0-6.', is_error: true },
        };
      }
      return {
        message: { type: 'sim:enqueue_build', payload: { robotType } },
        result: { tool_use_id: call.id, content: `Queued robot type ${robotType} for production.` },
      };
    }

    case 'build_building': {
      const buildingType = call.input.building_type as number;
      if (buildingType < 0 || buildingType > 8) {
        return {
          message: null,
          result: { tool_use_id: call.id, content: 'Invalid building type. Must be 0-8.', is_error: true },
        };
      }
      return {
        message: { type: 'sim:build_building', payload: { buildingType } },
        result: { tool_use_id: call.id, content: `Building type ${buildingType} construction initiated.` },
      };
    }

    case 'start_research': {
      const nodeId = call.input.node_id as string;
      if (!nodeId) {
        return {
          message: null,
          result: { tool_use_id: call.id, content: 'Missing node_id.', is_error: true },
        };
      }
      return {
        message: { type: 'sim:start_research', payload: { nodeId } },
        result: { tool_use_id: call.id, content: `Research started on "${nodeId}".` },
      };
    }

    case 'enqueue_recipe': {
      const recipeId = call.input.recipe_id as string;
      if (!recipeId) {
        return {
          message: null,
          result: { tool_use_id: call.id, content: 'Missing recipe_id.', is_error: true },
        };
      }
      return {
        message: { type: 'sim:enqueue_recipe', payload: { recipeId } },
        result: { tool_use_id: call.id, content: `Refining recipe "${recipeId}" queued.` },
      };
    }

    case 'recall_robot': {
      const robotEid = call.input.robot_eid as number;
      if (robotEid == null) {
        return {
          message: null,
          result: { tool_use_id: call.id, content: 'Missing robot_eid.', is_error: true },
        };
      }
      return {
        message: { type: 'sim:robot_order', payload: { robotEid, order: 'return_to_base' } },
        result: { tool_use_id: call.id, content: `Robot ${robotEid} ordered to return to base.` },
      };
    }

    default:
      return {
        message: null,
        result: { tool_use_id: call.id, content: `Unknown tool: ${call.name}`, is_error: true },
      };
  }
}
